**Why critical:** 100+ lines of scoring logic across 6 categories (0–100 total). Every point threshold, level cutoff, and alert condition is untested. A silent regression could corrupt the user's daily coaching output.

**Edge cases not covered:**
- `null` log input (no daily log yet)
- Maxed-out scores (all inputs at ceiling)
- Boundary values at each category cutoff (e.g., protein exactly at 80% of target)
- `extras` override fields (`recoveryScoreOverride`, `noDrinkStreakOverride`)

```typescript
// tests/daily-status.test.ts
import { describe, it, expect } from 'vitest';
import { generateDailyStatus } from '../lib/daily-status';
import type { DailyLog } from '../lib/storage';

const baseLog: DailyLog = {
  date: '2026-05-09',
  calories: 2200, calorieTarget: 2000,
  protein: 180, proteinTarget: 200,
  water: 3, weight: 185,
  sleepHours: 7.5, sleepQuality: 4,
  steps: 8000,
  screenTime: 120, instagramTime: 30,
  recoveryScore: 75, hrv: 62, restingHR: 52, strain: 8,
  mood: 4, confidence: 4,
  smokedToday: false, drankToday: false,
  notes: 'Felt good today.',
};

describe('generateDailyStatus', () => {
  it('returns a valid status for a null log', () => {
    const status = generateDailyStatus(null);
    expect(status.executionScore).toBeGreaterThanOrEqual(0);
    expect(status.executionScore).toBeLessThanOrEqual(100);
    expect(status.loggedToday).toBe(false);
    expect(status.missingInputs.length).toBeGreaterThan(0);
  });

  it('scores full execution for an ideal log', () => {
    const log: DailyLog = {
      ...baseLog,
      protein: 200, proteinTarget: 200,
      calories: 2000, calorieTarget: 2000,
      screenTime: 60, instagramTime: 15,
      mood: 5, confidence: 5,
      smokedToday: false, drankToday: false,
      recoveryScore: 90,
      notes: 'A'.repeat(60), // long notes
    };
    const status = generateDailyStatus(log, {
      stackTaken: 8, stackTotal: 8,
      voiceLogsToday: 2,
      weeklyWorkouts: 5,
    });
    expect(status.executionScore).toBeGreaterThanOrEqual(90);
  });

  it('generates a CRITICAL alert when protein is very low', () => {
    const status = generateDailyStatus({ ...baseLog, protein: 50, proteinTarget: 200 });
    const proteinAlerts = status.alerts.filter(a => a.category === 'nutrition');
    expect(proteinAlerts.length).toBeGreaterThan(0);
    expect(proteinAlerts[0].level).toBe('critical');
  });

  it('penalizes score when drankToday is true', () => {
    const soberStatus = generateDailyStatus(baseLog);
    const drankStatus = generateDailyStatus({ ...baseLog, drankToday: true });
    expect(drankStatus.executionScore).toBeLessThan(soberStatus.executionScore);
  });

  it('clamps executionScore to [0, 100]', () => {
    // Force all negatives
    const status = generateDailyStatus({
      ...baseLog, protein: 0, smokedToday: true, drankToday: true,
      screenTime: 600, mood: 1, confidence: 1, recoveryScore: 20,
    });
    expect(status.executionScore).toBeGreaterThanOrEqual(0);
  });

  it('uses recoveryScoreOverride when provided', () => {
    const withOverride = generateDailyStatus(
      { ...baseLog, recoveryScore: undefined },
      { recoveryScoreOverride: 95 }
    );
    const withoutOverride = generateDailyStatus(
      { ...baseLog, recoveryScore: undefined }
    );
    expect(withOverride.executionScore).toBeGreaterThan(withoutOverride.executionScore);
  });
});
```

