**Why critical:** Regex-based NLP on free-form text — the most brittle code in the project. No fuzz testing, no fixture library. Regressions are invisible.

**Edge cases not covered:**
- Multiple exercises in one transcript (array length)
- Fractional weights ("135.5 lbs")
- Ambiguous activity types ("did some lifting and a run")
- All-lowercase vs. mixed-case input
- Non-English numerals or abbreviations ("3x5 @ 225")
- Zero confidence when no signals match

```typescript
// tests/voice-parser.test.ts
import { describe, it, expect } from 'vitest';
import { parseTrainingFromVoiceLog, parseDailyFromVoiceLog } from '../lib/voice-parser';

describe('parseTrainingFromVoiceLog', () => {
  it('detects a strength session with exercises', () => {
    const result = parseTrainingFromVoiceLog(
      'Did my strength workout. Bench press 225 pounds for 3 sets of 5.'
    );
    expect(result.detected).toBe(true);
    expect(result.type).toBe('strength');
    expect(result.exercises.length).toBeGreaterThan(0);
    expect(result.exercises[0].exercise).toContain('Bench');
    expect(result.exercises[0].weight).toBe(225);
  });

  it('detects a run with distance', () => {
    const result = parseTrainingFromVoiceLog('Went for a 5.5 mile run this morning.');
    expect(result.detected).toBe(true);
    expect(result.type).toBe('run');
    expect(result.distance).toBe(5.5);
  });

  it('detects a rowing session with duration', () => {
    const result = parseTrainingFromVoiceLog('Did 20 minutes on the erg today.');
    expect(result.detected).toBe(true);
    expect(result.type).toBe('row');
    expect(result.duration).toBe(20);
  });

  it('returns low confidence for ambiguous transcript', () => {
    const result = parseTrainingFromVoiceLog('I did some stuff at the gym.');
    // Should detect but with low confidence
    if (result.detected) {
      expect(result.confidence).toBe('low');
    }
  });

  it('returns detected=false for a non-training transcript', () => {
    const result = parseTrainingFromVoiceLog('Today I ate 2200 calories and drank lots of water.');
    expect(result.detected).toBe(false);
  });

  it('handles empty string gracefully', () => {
    const result = parseTrainingFromVoiceLog('');
    expect(result.detected).toBe(false);
  });

  it('parses steps from a walk', () => {
    const result = parseTrainingFromVoiceLog('Went for a walk, hit 8500 steps.');
    expect(result.type).toBe('walk');
    expect(result.steps).toBe(8500);
  });
});

describe('parseDailyFromVoiceLog', () => {
  it('extracts calories and protein', () => {
    const result = parseDailyFromVoiceLog('Ate 2100 calories and 175 grams of protein today.');
    expect(result.detected).toBe(true);
    expect(result.fields.calories).toBe(2100);
    expect(result.fields.protein).toBe(175);
  });

  it('maps mood words to numbers', () => {
    const result = parseDailyFromVoiceLog('Feeling great today, mood is excellent.');
    expect(result.fields.mood).toBeGreaterThanOrEqual(4);
  });

  it('detects drankToday from text', () => {
    const result = parseDailyFromVoiceLog('Had a couple drinks at dinner tonight.');
    expect(result.fields.drankToday).toBe(true);
  });

  it('detects smokedToday from text', () => {
    const result = parseDailyFromVoiceLog('Smoked a cigarette after lunch, unfortunately.');
    expect(result.fields.smokedToday).toBe(true);
  });

  it('returns no fields for an unrelated transcript', () => {
    const result = parseDailyFromVoiceLog('The weather is nice today.');
    expect(result.detected).toBe(false);
    expect(Object.keys(result.fields).length).toBe(0);
  });
});
