**Why critical:** Progressive overload suggestions are user-trust features. Wrong weight suggestions erode trust silently — the user might not notice the bug until they've been following bad advice for weeks.

**Edge cases not covered:**
- Empty history (first time doing an exercise)
- Bodyweight exercise (weightUnit = 'bw')
- Compound vs. accessory increment split
- Fuzzy name matching ("bench press" vs "Bench Press" vs "Incline Bench")

```typescript
// tests/fitness.test.ts
import { describe, it, expect } from 'vitest';
import {
  suggestNextWeight,
  getExerciseHistory,
  getUniqueExercises,
  getThisWeekLogs,
} from '../lib/fitness';
import type { ActivityLog } from '../lib/fitness';

const makeLog = (overrides: Partial<ActivityLog> = {}): ActivityLog => ({
  id: crypto.randomUUID(),
  date: new Date().toISOString().split('T')[0],
  type: 'strength',
  label: 'Upper Body',
  duration: 60,
  source: 'manual',
  exercises: [],
  ...overrides,
});

describe('suggestNextWeight', () => {
  it('suggests +5 lb for a compound lift', () => {
    const logs = [
      makeLog({
        date: '2026-05-07',
        exercises: [{ exercise: 'Bench Press', sets: 3, reps: 5, weight: 225, weightUnit: 'lb' }],
      }),
    ];
    const suggestion = suggestNextWeight(logs, 'Bench Press');
    expect(suggestion).not.toBeNull();
    expect(suggestion!.weight).toBe(230);
    expect(suggestion!.increment).toBe(5);
  });

  it('suggests +2.5 lb for an accessory', () => {
    const logs = [
      makeLog({
        exercises: [{ exercise: 'Lateral Raise', sets: 3, reps: 12, weight: 25, weightUnit: 'lb' }],
      }),
    ];
    const suggestion = suggestNextWeight(logs, 'Lateral Raise');
    expect(suggestion!.increment).toBe(2.5);
  });

  it('returns null for empty history', () => {
    expect(suggestNextWeight([], 'Squat')).toBeNull();
  });

  it('returns null for bodyweight exercise with no weight', () => {
    const logs = [
      makeLog({
        exercises: [{ exercise: 'Pull-up', sets: 3, reps: 8, weight: 0, weightUnit: 'bw' }],
      }),
    ];
    expect(suggestNextWeight(logs, 'Pull-up')).toBeNull();
  });
});

describe('getExerciseHistory', () => {
  it('returns history sorted newest first', () => {
    const logs = [
      makeLog({ date: '2026-05-01', exercises: [{ exercise: 'Squat', sets: 3, reps: 5, weight: 275, weightUnit: 'lb' }] }),
      makeLog({ date: '2026-05-08', exercises: [{ exercise: 'Squat', sets: 3, reps: 5, weight: 285, weightUnit: 'lb' }] }),
    ];
    const history = getExerciseHistory(logs, 'Squat');
    expect(history[0].weight).toBe(285);
    expect(history[1].weight).toBe(275);
  });

  it('matches case-insensitively', () => {
    const logs = [makeLog({ exercises: [{ exercise: 'bench press', sets: 3, reps: 5, weight: 200, weightUnit: 'lb' }] })];
    const history = getExerciseHistory(logs, 'Bench Press');
    expect(history.length).toBe(1);
  });

  it('returns empty array when exercise not found', () => {
    const logs = [makeLog({ exercises: [{ exercise: 'Squat', sets: 3, reps: 5, weight: 200, weightUnit: 'lb' }] })];
    expect(getExerciseHistory(logs, 'Deadlift')).toEqual([]);
  });
});

describe('getUniqueExercises', () => {
  it('deduplicates across multiple logs', () => {
    const logs = [
      makeLog({ exercises: [{ exercise: 'Bench Press', sets: 3, reps: 5, weight: 200, weightUnit: 'lb' }] }),
      makeLog({ exercises: [{ exercise: 'Bench Press', sets: 3, reps: 5, weight: 205, weightUnit: 'lb' }, { exercise: 'Squat', sets: 3, reps: 5, weight: 275, weightUnit: 'lb' }] }),
    ];
    const exercises = getUniqueExercises(logs);
    expect(exercises).toContain('Bench Press');
    expect(exercises).toContain('Squat');
    expect(exercises.filter(e => e === 'Bench Press').length).toBe(1);
  });

  it('returns empty array for logs with no exercises', () => {
    expect(getUniqueExercises([makeLog()])).toEqual([]);
  });
});
```

