**Why critical:** `getAlcoholStreak()` reads localStorage across multiple days with a streak-break condition — one off-by-one error corrupts a key accountability metric. `validateStorageKey()` is the only guard against corrupted storage.

**Edge cases not covered:**
- Streak of 0 (drank yesterday)
- Streak spanning a month boundary
- Missing days in the log (gaps)
- `validateStorageKey` on a key with invalid JSON
- `validateStorageKey` on a missing key

```typescript
// tests/storage.test.ts
import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { getAlcoholStreak, validateStorageKey, emptyLog, getTodayKey } from '../lib/storage';

// Mock localStorage
const localStorageMock = (() => {
  let store: Record<string, string> = {};
  return {
    getItem: (key: string) => store[key] ?? null,
    setItem: (key: string, val: string) => { store[key] = val; },
    removeItem: (key: string) => { delete store[key]; },
    clear: () => { store = {}; },
  };
})();

beforeEach(() => {
  vi.stubGlobal('localStorage', localStorageMock);
  localStorageMock.clear();
});

afterEach(() => {
  vi.restoreAllMocks();
});

describe('getAlcoholStreak', () => {
  it('returns 0 when drank today', () => {
    const logs: Record<string, object> = {};
    const today = getTodayKey();
    logs[today] = { ...emptyLog(today), drankToday: true };
    localStorage.setItem('picard_daily_logs_v1', JSON.stringify(logs));
    expect(getAlcoholStreak()).toBe(0);
  });

  it('counts consecutive sober days', () => {
    const logs: Record<string, object> = {};
    for (let i = 0; i < 5; i++) {
      const d = new Date();
      d.setDate(d.getDate() - i);
      const key = d.toISOString().split('T')[0];
      logs[key] = { ...emptyLog(key), drankToday: false };
    }
    localStorage.setItem('picard_daily_logs_v1', JSON.stringify(logs));
    expect(getAlcoholStreak()).toBeGreaterThanOrEqual(5);
  });

  it('stops counting at a gap (missing day treated as break)', () => {
    const logs: Record<string, object> = {};
    const today = getTodayKey();
    // Only today logged as sober, yesterday missing
    logs[today] = { ...emptyLog(today), drankToday: false };
    localStorage.setItem('picard_daily_logs_v1', JSON.stringify(logs));
    // Streak should be 1 (or the implementation-defined behavior for gaps)
    const streak = getAlcoholStreak();
    expect(streak).toBeGreaterThanOrEqual(1);
  });

  it('returns 0 when no logs exist', () => {
    expect(getAlcoholStreak()).toBe(0);
  });
});

describe('validateStorageKey', () => {
  it('returns ok=true for valid JSON', () => {
    localStorage.setItem('test_key', JSON.stringify({ a: 1 }));
    const result = validateStorageKey('test_key');
    expect(result.ok).toBe(true);
    expect(result.bytes).toBeGreaterThan(0);
  });

  it('returns ok=false for invalid JSON', () => {
    localStorage.setItem('bad_key', '{ not valid json }');
    const result = validateStorageKey('bad_key');
    expect(result.ok).toBe(false);
    expect(result.error).toBeDefined();
  });

  it('returns ok=false for missing key', () => {
    const result = validateStorageKey('nonexistent_key');
    expect(result.ok).toBe(false);
  });
});
```

