**Why critical:** Project detection from voice is the glue between voice logs and project management. Alias mismatches mean updates get dropped silently.

```typescript
// tests/project-parser.test.ts
import { describe, it, expect } from 'vitest';
import { parseProjectsFromVoiceLog, detectProgressBump, extractNextAction } from '../lib/project-parser';

describe('detectProgressBump', () => {
  it('returns 5 for completed language', () => {
    expect(detectProgressBump('I finished the scene today.')).toBe(5);
  });
  it('returns 3 for progress language', () => {
    expect(detectProgressBump('Made good progress on the script.')).toBe(3);
  });
  it('returns 1 for minimal effort language', () => {
    expect(detectProgressBump('Worked on it a bit.')).toBe(1);
  });
