    const action = extractNextAction('I need to call the venue by Friday.');
    expect(action).toContain('call the venue');
  });
  it('extracts action after "going to"', () => {
    const action = extractNextAction("Tomorrow I'm going to finish the lighting design.");
    expect(action).toContain('finish the lighting design');
