**Why critical:** This is the core AI reasoning engine. No tests means any refactor could break the scoring/insight system undetected.

**Missing error handling tests:**
- All-null input (no logs, no activity, no stack)
- Projects array empty
- `alcoholStreak` = 0

```typescript
// tests/xodus-brain.test.ts
import { describe, it, expect } from 'vitest';
import { runXodusBrain } from '../lib/xodus/brain';
import type { XodusBrainInput } from '../lib/xodus/brain';

const emptyInput: XodusBrainInput = {
  dailyLog: null,
  weekLogs: [],
  todayLogs: [],
  stackItems: [],
  projects: [],
  voiceLogsToday: 0,
  uploadsToday: 0,
  alcoholStreak: 0,
};

describe('runXodusBrain', () => {
  it('runs without throwing on empty input', () => {
    expect(() => runXodusBrain(emptyInput)).not.toThrow();
  });

  it('returns a valid structure on empty input', () => {
    const output = runXodusBrain(emptyInput);
    expect(output.executionScore).toBeGreaterThanOrEqual(0);
    expect(output.executionScore).toBeLessThanOrEqual(100);
    expect(Array.isArray(output.insights)).toBe(true);
    expect(Array.isArray(output.brief)).toBe(true);
  });

  it('generates a CRITICAL nutrition insight when protein is very low', () => {
    const output = runXodusBrain({
      ...emptyInput,
      dailyLog: {
        date: '2026-05-09',
        protein: 30, proteinTarget: 200,
        calories: 800, calorieTarget: 2000,
      } as any,
    });
    const nutritionInsights = output.insights.filter(i => i.domain === 'nutrition');
    expect(nutritionInsights.length).toBeGreaterThan(0);
    expect(nutritionInsights[0].level).toBe('critical');
  });

  it('sorts insights with critical before warning before info', () => {
    const output = runXodusBrain({
      ...emptyInput,
      dailyLog: {
        date: '2026-05-09',
        protein: 30, proteinTarget: 200,
        recoveryScore: 30,
      } as any,
    });
    const levels = output.insights.map(i => i.level);
    const levelOrder = { critical: 0, warning: 1, info: 2, positive: 3 };
    for (let i = 0; i < levels.length - 1; i++) {
      expect(levelOrder[levels[i]]).toBeLessThanOrEqual(levelOrder[levels[i + 1]]);
    }
  });

  it('includes positives when all metrics are good', () => {
    const output = runXodusBrain({
      ...emptyInput,
      alcoholStreak: 30,
      dailyLog: {
        date: '2026-05-09',
        recoveryScore: 92, hrv: 70, restingHR: 48,
        protein: 200, proteinTarget: 200,
        calories: 2000, calorieTarget: 2000,
        smokedToday: false, drankToday: false,
        mood: 5, confidence: 5,
      } as any,
    });
    expect(output.positives.length).toBeGreaterThan(0);
  });
});
