These scenarios have **no defensive code and no tests**:

| Scenario | Where | Risk |
|---|---|---|
| `localStorage` throws `QuotaExceededError` | `setStorage()` | Silent data loss |
| `JSON.parse` on corrupted log entry | `getStorage()` | Runtime crash |
| Negative `calories` or `protein` passed to scoring | `generateDailyStatus()` | Negative scores |
| `targetDate` is not a valid date string | `daysUntil()` | `NaN` days |
| `parseTrainingFromVoiceLog` on 10,000-char input | `voice-parser.ts` | Regex backtracking / hang |

```typescript
// tests/error-handling.test.ts
import { describe, it, expect, vi } from 'vitest';
import { getStorage, setStorage } from '../lib/storage';
import { daysUntil } from '../lib/projects';
import { generateDailyStatus } from '../lib/daily-status';

describe('storage error handling', () => {
  it('getStorage returns fallback when localStorage throws', () => {
    vi.stubGlobal('localStorage', {
      getItem: () => { throw new Error('SecurityError'); },
      setItem: vi.fn(),
    });
    const result = getStorage('any_key', []);
    expect(result).toEqual([]);
    vi.restoreAllMocks();
  });

  it('getStorage returns fallback for corrupted JSON', () => {
    vi.stubGlobal('localStorage', {
      getItem: () => '{ broken json',
      setItem: vi.fn(),
    });
    expect(getStorage('key', 'default')).toBe('default');
    vi.restoreAllMocks();
  });
});

describe('daysUntil error handling', () => {
  it('handles an invalid date string without crashing', () => {
    // Should not throw — behavior (NaN, 0, or sentinel) should be defined
    expect(() => daysUntil('not-a-date')).not.toThrow();
  });
});

describe('generateDailyStatus with invalid data', () => {
  it('does not produce negative executionScore for negative inputs', () => {
    const status = generateDailyStatus({
      date: '2026-05-09',
      calories: -500, protein: -100, water: -1,
    } as any);
    expect(status.executionScore).toBeGreaterThanOrEqual(0);
  });
});
